# Build a TanStack Query user card

Implement `App` in `src/App.tsrx` with `@octanejs/tanstack-query`.

`App` receives a `QueryClient`, a `userId`, and an injected
`loadUser(userId)` function. Provide the client with `QueryClientProvider` and
load the user with `useQuery`. Use a query key that includes the current user
ID so changing `userId` loads and displays the new user. Disable retries.

While unresolved, render `Loading user…` with `role="status"`. On success,
render the user's name as a heading and their email. On failure, render
`Could not load user: message` with `role="alert"`. Do not call the loader
outside the query, create a replacement client, or mirror query data into local
state. Only edit `src/App.tsrx`.

Starter src/App.tsrx:

```tsx
import type { QueryClient } from '@octanejs/tanstack-query';

export interface User {
	id: string;
	name: string;
	email: string;
}

export function App(_props: {
	client: QueryClient;
	userId: string;
	loadUser: (userId: string) => Promise<User>;
}) @{
	<section aria-label="User card">
		<p role="status">Loading user…</p>
	</section>
}
```

import { QueryClientProvider, useQuery } from '@octanejs/tanstack-query';
import type { QueryClient } from '@octanejs/tanstack-query';

export interface User {
	id: string;
	name: string;
	email: string;
}

interface UserCardProps {
	userId: string;
	loadUser: (userId: string) => Promise<User>;
}

function UserCard(props: UserCardProps) @{
	const query = useQuery({
		queryKey: ['user', props.userId],
		queryFn: () => props.loadUser(props.userId),
		retry: false,
	});

	<section aria-label="User card">
		@if (query.isPending) {
			<p role="status">Loading user…</p>
		} @else if (query.isError) {
			<p role="alert">{'Could not load user: ' + (query.error as Error).message}</p>
		} @else {
			<>
				<h1>
					{query.data.name as string}
				</h1>
				<p>
					{query.data.email as string}
				</p>
			</>
		}
	</section>
}

export function App(props: {
	client: QueryClient;
	userId: string;
	loadUser: (userId: string) => Promise<User>;
}) @{
	<QueryClientProvider client={props.client}>
		<UserCard userId={props.userId} loadUser={props.loadUser} />
	</QueryClientProvider>
}

import { create } from '@octanejs/zustand';

const products = [
	{ id: 'coffee', name: 'Coffee', priceCents: 1250 },
	{ id: 'tea', name: 'Tea', priceCents: 500 },
] as const;

type ProductId = (typeof products)[number]['id'];

interface CartState {
	quantities: Partial<Record<ProductId, number>>;
	add: (id: ProductId) => void;
	decrease: (id: ProductId) => void;
	clear: () => void;
}

const useCartStore = create<CartState>(
	(set) => ({
		quantities: {},
		add: (id) => set(
			(state) => ({
				quantities: {
					...state.quantities,
					[id]: (state.quantities[id] ?? 0) + 1,
				},
			}),
		),
		decrease: (id) => set((state) => {
			const quantities = { ...state.quantities };
			const next = (quantities[id] ?? 0) - 1;
			if (next > 0) quantities[id] = next;
			else delete quantities[id];
			return { quantities };
		}),
		clear: () => set({ quantities: {} }),
	}),
);

function formatPrice(cents: number): string {
	return '£' + (cents / 100).toFixed(2);
}

export function App() @{
	const quantities = useCartStore((state) => state.quantities);
	const add = useCartStore((state) => state.add);
	const decrease = useCartStore((state) => state.decrease);
	const clear = useCartStore((state) => state.clear);
	const lines = products.filter((product) => (quantities[product.id] ?? 0) > 0);
	const total = products.reduce(
		(sum, product) => sum + product.priceCents * (quantities[product.id] ?? 0),
		0,
	);

	<main>
		<h1>Shopping cart</h1>
		<div>
			@for (const product of products; key product.id) {
				<button aria-label={'Add ' + product.name} onClick={() => add(product.id)}>
					{'Add ' + product.name}
				</button>
			}
		</div>
		@if (lines.length === 0) {
			<p>Cart empty</p>
		} @else {
			<ul>
				@for (const product of lines; key product.id) {
					<li>
						<span>{product.name + ' × ' + (quantities[product.id] ?? 0)}</span>
						<button aria-label={'Decrease ' + product.name} onClick={() => decrease(product.id)}>
							{'Decrease ' + product.name}
						</button>
					</li>
				}
			</ul>
		}
		<p>{'Total: ' + formatPrice(total)}</p>
		<button disabled={lines.length === 0} onClick={clear}>Clear cart</button>
	</main>
}

# Suspense product details

Implement `src/App.tsrx` as an asynchronous product-details panel.

The module must continue to export the `Product` interface and `App` component.

Requirements:

- `App` receives a `productId` and a `loadProduct(id)` function.
- Start the request by calling `loadProduct` with the active product ID and
  unwrap it with Octane's `use()` API.
- Use TSRX `@try`, `@pending`, and `@catch` arms.
- While pending, render `.loading` with the text `Loading product…`.
- On success, render an `<article class="product">` whose `data-product-id`
  matches the product. It contains the product name in an `<h2>` and its price
  in `.price`, formatted as dollars with exactly two decimal places.
- On rejection, remove the loading and success content and render a
  `role="alert"` element with class `error` containing the original error
  message. Non-Error rejection values must be converted with `String(...)`.
- Re-rendering with the same ID must not recreate the request. Changing the ID
  must start the new request and show the pending arm again.

Do not edit the grader or add dependencies.

