import { useState } from 'octane';

export interface Member {
	id: string;
	name: string;
	bio: string;
}

const members: Member[] = [
	{ id: 'ada', name: 'Ada', bio: 'Designs accessible systems' },
	{ id: 'grace', name: 'Grace', bio: 'Operates cloud services' },
];

export function MemberCard(props: {
	member: Member;
	applause: number;
	onApplaud: (id: string) => void;
}) @{
	const [detailsOpen, setDetailsOpen] = useState(false);

	<article data-member-id={props.member.id}>
		<h2>
			{props.member.name as string}
		</h2>
		<output aria-label={'Applause ' + props.member.name}>
			{props.applause as string}
		</output>
		<button
			aria-label={(detailsOpen ? 'Hide details ' : 'Show details ') + props.member.name}
			onClick={() => setDetailsOpen((open) => !open)}
		>
			{detailsOpen ? 'Hide details' : 'Show details'}
		</button>
		<button
			aria-label={'Applaud twice ' + props.member.name}
			onClick={() => {
				props.onApplaud(props.member.id);
				props.onApplaud(props.member.id);
			}}
		>
			Applaud twice
		</button>
		@if (detailsOpen) {
			<p>
				{props.member.bio as string}
			</p>
		}
	</article>
}

export function TeamSummary(props: { total: number }) @{
	<output aria-label="Total applause">
		{props.total as string}
	</output>
}

export function App() @{
	const [applause, setApplause] = useState<Record<string, number>>({ ada: 0, grace: 0 });
	const [reversed, setReversed] = useState(false);
	const orderedMembers =
		reversed ? [...members].reverse() : members;
	const total = Object.values(applause).reduce((sum, count) => sum + count, 0);
	const applaud = (id: string) => {
		setApplause(
			(current) => ({
				...current,
				[id]: (current[id] ?? 0) + 1,
			}),
		);
	};

	<main>
		<h1>Team board</h1>
		<button onClick={() => setReversed((value) => !value)}>Reverse team</button>
		<TeamSummary total={total} />
		<section aria-label="Team members">
			@for (const member of orderedMembers; key member.id) {
				<MemberCard member={member} applause={applause[member.id] ?? 0} onApplaud={applaud} />
			}
		</section>
	</main>
}

# Derive a live invoice with inferred hook dependencies

Implement `src/App.tsrx` and export a component named `App` with these props:

```ts
{
	quantity: number;
	unitPrice: number;
	discount: number;
	onTotal: (total: number) => void;
}
```

This task exercises Octane's compiler-inferred dependencies. In React, omitting
a dependency array makes an effect run after every render. In Octane, omission
asks the compiler to derive the dependencies from lexical captures.

Requirements:

- Compute `subtotal` as `quantity * unitPrice` with `useMemo`.
- Compute `total` as `Math.max(0, subtotal - discount)` with a second `useMemo`.
- Omit the dependency array from both `useMemo` calls. Do not manually write an
  array or pass `null`.
- Call `onTotal(total)` from a `useEffect`, also with its dependency array
  omitted. The effect must react to both the total and a replacement `onTotal`
  callback, while avoiding unrelated repeats.
- Render the quantity in an output labelled `Quantity`, the subtotal in an
  output labelled `Subtotal`, and the total in an output labelled `Total`.
- Format subtotal and total as fixed two-decimal strings without a currency
  symbol.

Keep all implementation code in `src/App.tsrx`. Do not add dependencies or edit
the grader.

Starter src/App.tsrx:

```tsx
import { useEffect, useMemo } from 'octane';

export function App(props: {
	quantity: number;
	unitPrice: number;
	discount: number;
	onTotal: (total: number) => void;
}) @{
	const subtotal = useMemo(() => props.quantity * props.unitPrice, []);
	const total = useMemo(() => Math.max(0, subtotal - props.discount), []);

	useEffect(() => {
		props.onTotal(total);
	}, []);

	<section aria-label="Invoice summary">
		<output aria-label="Quantity">
			{props.quantity as string}
		</output>
		<output aria-label="Subtotal">{subtotal.toFixed(2)}</output>
		<output aria-label="Total">{total.toFixed(2)}</output>
	</section>
}
```

